class Solution:
    def wordSquares(self, words):
        n = len(words)
        result = []
        for i in range(n):
            top = words[i]
            for j in range(n):
                if j == i:
                    continue
                left = words[j]
                if left[0] != top[0]:
                    continue
                for k in range(n):
                    if k == i or k == j:
                        continue
                    right = words[k]
                    if right[0] != top[3]:
                        continue
                    for l in range(n):
                        if l == i or l == j or l == k:
                            continue
                        bottom = words[l]
                        if bottom[0] == left[3] and bottom[3] == right[3]:
                            result.append([top, left, right, bottom])
        result.sort()
        return result

