from collections import defaultdict

class Solution:
    def wordSquares(self, words):
        by_first = defaultdict(list)
        for w in words:
            by_first[w[0]].append(w)
        result = []
        for top in words:
            for left in by_first.get(top[0], []):
                if left == top:
                    continue
                for right in by_first.get(top[3], []):
                    if right == top or right == left:
                        continue
                    for bottom in by_first.get(left[3], []):
                        if bottom == top or bottom == left or bottom == right:
                            continue
                        if bottom[3] == right[3]:
                            result.append([top, left, right, bottom])
        result.sort()
        return result

