var wordSquares = function(words) {
    const byFirst = new Map();
    for (const w of words) {
        const key = w[0];
        if (!byFirst.has(key)) byFirst.set(key, []);
        byFirst.get(key).push(w);
    }
    const result = [];
    for (const top of words) {
        for (const left of byFirst.get(top[0]) || []) {
            if (left === top) continue;
            for (const right of byFirst.get(top[3]) || []) {
                if (right === top || right === left) continue;
                for (const bottom of byFirst.get(left[3]) || []) {
                    if (bottom === top || bottom === left || bottom === right) continue;
                    if (bottom[3] === right[3]) {
                        result.push([top, left, right, bottom]);
                    }
                }
            }
        }
    }
    result.sort((a, b) => {
        for (let i = 0; i < 4; i++) {
            if (a[i] < b[i]) return -1;
            if (a[i] > b[i]) return 1;
        }
        return 0;
    });
    return result;
};
